const form = $input.first().json;
const topic = form.Topic;
const depth = form.Depth || '标准 (5 路搜索)';
const n = depth.startsWith('简略') ? 3 : depth.startsWith('深度') ? 8 : 5;

const queriesBy = {
  3: [
    `${topic} 是什么 介绍`,
    `${topic} 最新进展 2026`,
    `${topic} 竞品 对比`
  ],
  5: [
    `${topic} 是什么 介绍`,
    `${topic} 历史 发展`,
    `${topic} 最新进展 2026`,
    `${topic} 竞品 对比`,
    `${topic} 优势 劣势 评价`
  ],
  8: [
    `${topic} 是什么 介绍`,
    `${topic} 历史 起源 发展`,
    `${topic} 最新进展 2026`,
    `${topic} 技术原理 实现`,
    `${topic} 商业模式 盈利`,
    `${topic} 竞品 对比 替代`,
    `${topic} 优势 劣势 用户评价`,
    `${topic} 未来 趋势 预测`
  ]
};

const list = queriesBy[n];
return list.map(q => ({ json: { query: q } }));

const query = $('Build Search Queries').item.json.query;
const results = ($json.results || []).map(r => ({
  title: r.title,
  url: r.url,
  content: r.content ? String(r.content).slice(0, 800) : '',
  score: r.score
