const article = $input.first().json.choices[0].message.content;
const research = $('Save Research Output').first().json.research;
const form = $('On form submission').first().json;
const searches = $('Aggregate Research').first().json.searches || [];

const output = form.Output || '两者都要';
const showResearch = output !== '仅文章';
const showArticle = output !== '仅研究';

const esc = (s) => String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

function md2html(raw) {
  let h = esc(raw);
  h = h.replace(/^#### (.*)$/gm, '<h4>$1</h4>');
  h = h.replace(/^### (.*)$/gm, '<h3>$1</h3>');
  h = h.replace(/^## (.*)$/gm, '<h2>$1</h2>');
  h = h.replace(/^# (.*)$/gm, '<h1>$1</h1>');
  h = h.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
  h = h.replace(/(^|[^*])\*([^*\n]+?)\*([^*]|$)/g, '$1<em>$2</em>$3');
  h = h.replace(/`([^`\n]+)`/g, '<code>$1</code>');
  h = h.replace(/^> (.*)$/gm, '<blockquote>$1</blockquote>');
  h = h.replace(/^(?:- |\* )(.*)$/gm, '<li>$1</li>');
  h = h.replace(/(<li>[\s\S]*?<\/li>)(?!\s*<li>)/g, '<ul>$1</ul>');
  return h.split(/\n{2,}/).map(b => {
    if (/^<(h\d|ul|blockquote)/i.test(b.trim())) return b;
    return '<p>' + b.replace(/\n/g, '<br/>') + '</p>';
  }).join('\n');
}

const eyebrowStyle = "font-family:'SF Mono',ui-monospace,monospace;font-size:11px;font-weight:500;letter-spacing:0.18em;text-transform:uppercase;color:#3A78C2";
const nameStyle = "font-family:Georgia,serif;font-style:italic;font-weight:400;letter-spacing:0;text-transform:capitalize;color:#1A1D20;font-size:13px;padding-left:4px";
const proseStyle = "font-size:16px;line-height:1.75;color:#4A5057;max-width:62ch";

const sourcesList = searches.flatMap(s => s.results || []).map(r => `<li style="margin:4px 0"><a href="${esc(r.url)}" target="_blank" style="color:#3A78C2;text-decoration:none;font-size:13px">${esc(r.title)}</a></li>`).join('');

const researchCard = showResearch ? `<article style="background:#fff;border:1px solid #ECEEE8;border-radius:14px;box-shadow:0 1px 2px rgba(16,24,40,0.04);padding:36px 40px;margin-bottom:24px;position:relative;overflow:hidden"><div style="height:4px;background:linear-gradient(120deg,#4A90D9 0%,#6FC9E8 35%,#B4A7E8 68%,#F0B4D8 100%);position:absolute;top:0;left:0;right:0"></div><div style="${eyebrowStyle};margin:8px 0 14px">RESEARCH · <em style="${nameStyle}">hv-analysis</em></div><div style="${proseStyle}">${md2html(research)}</div><details style="margin-top:24px;padding-top:18px;border-top:1px solid #E2E4DD"><summary style="cursor:pointer;${eyebrowStyle};margin:0 0 12px">SOURCES · ${searches.reduce((n, s) => n + (s.results || []).length, 0)} 条</summary><ul style="padding-left:20px;margin:8px 0 0">${sourcesList}</ul></details></article>` : '';

const articleCard = showArticle ? `<article style="background:#fff;border:1px solid #ECEEE8;border-radius:14px;box-shadow:0 6px 20px -6px rgba(16,24,40,0.08);padding:48px 56px"><div style="${eyebrowStyle};margin:0 0 14px">ARTICLE · <em style="${nameStyle}">khazix-writer</em></div><div style="${proseStyle}">${md2html(article)}</div></article>` : '';

const body = `<div style="max-width:880px;margin:60px auto;padding:0 24px;font-family:-apple-system,BlinkMacSystemFont,'PingFang SC',sans-serif;color:#1A1D20;line-height:1.7"><div style="margin-bottom:32px"><div style="${eyebrowStyle};margin:0 0 12px">TOPIC · ${esc(form.Depth)}</div><blockquote style="border-left:2px solid #4A90D9;padding:8px 0 8px 20px;margin:0;font-family:Georgia,serif;font-style:italic;font-size:21px;line-height:1.5;color:#1A1D20">${esc(form.Topic)}</blockquote></div>${researchCard}${articleCard}<div style="display:flex;align-items:center;gap:16px;margin:40px 0 0;padding-top:28px;border-top:1px solid #E2E4DD"><span style="flex:1;height:1px;background:#E2E4DD"></span><span style="font-family:Georgia,serif;font-style:italic;font-size:12px;color:#8B8F86">慢慢来 · 静水深流</span><span style="flex:1;height:1px;background:#E2E4DD"></span></div></div>`;

return [{ json: { formSubmittedText: body } }];
